B.MD=new A.cv("Endplate Noise (MEPPs)","Monophasic negative (upward) potentials causing a continuous 'seashell' roaring sound in the background.")
B.ML=new A.cv("Endplate Spikes","Biphasic potentials caused by needle irritation. They look like fibrillations but ALWAYS have an initial negative (upward) deflection.")
B.N3=new A.cv("The Golden Rule","Endplate potentials start UP (negative). Fibrillation potentials start DOWN (positive). Never call a fib if it starts upward.")
B.N6=new A.cv("The Sound","An irregular, painful 'sputtering' sound. The patient will likely tell you that spot hurts.")
B.a27=s([B.MD,B.ML,B.N3,B.N6],t.LK)
B.aff=new A.kg("Normal Spontaneous Activity: The Endplate","When your needle tip is sitting directly in the neuromuscular junction, you will irritate the terminal nerve twigs. You must learn to recognize this so you don't confidently misdiagnose the patient with active denervation.","2QgTg8f0pHE",B.a27)
B.a6s=s([B.aff],t.ND)
B.a18=s([0.001200833568784504,0.002389694492170889,0.0002795742885861124],t.n)
B.a4P=s([0.0005891086651375999,0.0029785502573438758,0.0003270666104008398],t.n)
