c2=A.a([A.Y(ac9,d9),A.Y(ad0,"S1 radiculopathy would typically cause an absent Achilles reflex and denervation in proximal S1 muscles (Gastrocnemius, Gluteus Maximus); here both are normal."),A.Y(ac8,"Primarily a pain syndrome at the calcaneal insertion; would not cause the significant intrinsic muscle denervation and plantar NCS abnormalities seen here."),A.Y(ac1,"Usually presents with symmetric 'stocking-glove' distribution and abnormal Sural SNAPs; here findings are focal and the Sural is normal."),A.Y(p7,"Sciatic lesions would involve the peroneal division (TA, EHL) and the Sural SNAP; here those are entirely spared.")],ae9)
