c3=A.a([A.Y(ad0,d9),A.Y(p7,"Sciatic lesions would typically involve peroneal muscles (TA, EHL) and the Sural SNAP; here those are entirely spared."),A.Y(ad5,"A diagnosis of exclusion; would spare the paraspinal muscles and typically spares the S1 roots' contributions to the Gluteus Maximus (inferior gluteal nerve branches proximal to the piriformis)."),A.Y(p8,"Plexopathy would involve multiple root levels (L5, S1, S2) and usually shows an abnormal Sural SNAP (post-ganglionic); here Sural is normal."),A.Y(ad6,"primarily a pain syndrome without the neurologic deficits (absent reflex, abnormal EMG) seen here.")],ae9)
